(function(){"use strict";document.addEventListener("click",function(e){var r=e.target.closest('a[href*="#"]');if(r){var t=r.getAttribute("href");if(!(t==="#"||t==="#0")){var o=t.indexOf("#")!==-1?t.slice(t.indexOf("#")):null;if(o){var l=document.querySelector(o);if(l){e.preventDefault();var s=l.getBoundingClientRect().top+window.scrollY-80;window.scrollTo({top:s,behavior:"smooth"})}}}}});var n=document.getElementById("site-header");n&&window.addEventListener("scroll",function(){n.classList.toggle("scrolled",window.scrollY>50)},{passive:!0});var i=document.getElementById("reading-progress-bar");i&&window.addEventListener("scroll",function(){var e=document.documentElement.scrollHeight-window.innerHeight,r=e>0?window.scrollY/e*100:0;i.style.width=r+"%"},{passive:!0})})();
